// LinkedIn profiles to monitor (Fri 8am PT). All slugs verified active 2026-04-24.
// total_posts: how many recent posts to fetch (Apify dedups against Notion downstream).
return [
  // HIGH: prolific + strong topical alignment
  { json: { username: 'gregstuart',     display_name: 'Greg Stuart',           total_posts: 20, tier: 'high' } },
  { json: { username: 'oliver-patel',   display_name: 'Oliver Patel',          total_posts: 15, tier: 'high' } },
  { json: { username: 'emollick',       display_name: 'Ethan Mollick',         total_posts: 30, tier: 'high' } },
  { json: { username: 'alliekmiller',   display_name: 'Allie K. Miller',       total_posts: 25, tier: 'high' } },
  { json: { username: 'kozyrkov',       display_name: 'Cassie Kozyrkov',       total_posts: 20, tier: 'high' } },
  { json: { username: 'carolineg',      display_name: 'Caroline Giegerich',    total_posts: 15, tier: 'high' } },
  { json: { username: 'bricechallamel', display_name: 'Brice Challamel',       total_posts: 15, tier: 'high' } },
  // MEDIUM: lower volume or temporary noise
  { json: { username: 'reid-blackman',  display_name: 'Reid Blackman',         total_posts: 20, tier: 'medium' } },
  { json: { username: 'andrewyng',      display_name: 'Andrew Ng',             total_posts: 10, tier: 'medium' } },
  // LOW: filter aggressively (mostly product launches, useful as Google/DeepMind pulse)
  { json: { username: 'logankilpatrick', display_name: 'Logan Kilpatrick',     total_posts: 20, tier: 'low' } },
];

// Apify apimaestro/linkedin-profile-posts returns ONE ITEM PER POST (190 items total for 10 profiles).
// Each item has nested {urn:{activity_urn,...}, posted_at:{date,timestamp,...}, author:{...}, stats:{...}}
const TIER_BY_USERNAME = {
  'gregstuart': 'high',
  'oliver-patel': 'high',
  'emollick': 'high',
  'alliekmiller': 'high',
  'kozyrkov': 'high',
  'carolineg': 'high',
  'bricechallamel': 'high',
  'reid-blackman': 'medium',
  'andrewyng': 'medium',
  'logankilpatrick': 'low',
};
const WINDOW_DAYS = 7;
const cutoff = Date.now() - WINDOW_DAYS * 24 * 60 * 60 * 1000;
const items = $input.all();
const out = [];
for (const item of items) {
  const p = item.json;
  const text = p.text || '';
  if (!text || text.length < 80) continue;
  // posted_at: object {date, relative, timestamp} OR plain string
  let timestamp = 0;
  if (p.posted_at && typeof p.posted_at === 'object') {
    timestamp = p.posted_at.timestamp || (p.posted_at.date ? new Date(p.posted_at.date).getTime() : 0);
  } else if (typeof p.posted_at === 'string') {
    timestamp = new Date(p.posted_at).getTime();
  }
  if (!timestamp || isNaN(timestamp) || timestamp < cutoff) continue;
  const url = p.url || '';
  let urn = '';
  if (p.urn && typeof p.urn === 'object' && p.urn.activity_urn) urn = 'urn:li:activity:' + p.urn.activity_urn;
  else if (p.full_urn) urn = p.full_urn;
  else urn = url;
  if (!urn) continue;
  const author = p.author || {};
  const author_username = author.username || '';
  const author_name = ((author.first_name || '') + ' ' + (author.last_name || '')).trim() || author_username;
  const stats = p.stats || {};
  out.push({ json: {
    urn: String(urn),
    url: url,
    text: text.substring(0, 12000),
    author_username: author_username,
    author_name: author_name,
    author_headline: author.headline || '',
    posted_at: new Date(timestamp).toISOString(),
    reactions: stats.reactions || stats.likes || stats.total_reactions || 0,
    comments: stats.comments || stats.comments_count || 0,
    reposts: stats.reposts || stats.shares || 0,
    tier: TIER_BY_USERNAME[author_username] || 'medium',
  }});
}
return out;

// Filter out posts already in Notion. We use the post URL embedded in the Episode rich_text link.
const posts = $('Parse + Filter Posts').all().map(it => it.json);
const existing = $input.all();
const existingUrns = new Set();
const existingUrls = new Set();
for (const e of existing) {
  const results = (e.json.results) || [];
  for (const page of results) {
    // The Episode property is a rich_text where text[].link.url is the post URL
    const ep = (page.properties && page.properties.Episode && page.properties.Episode.rich_text) || [];
    for (const seg of ep) {
      const u = (seg.text && seg.text.link && seg.text.link.url) || '';
      if (u) existingUrls.add(u);
    }
    // Also check the Comment property for URN
    const cmt = (page.properties && page.properties.Comment && page.properties.Comment.rich_text) || [];
    for (const seg of cmt) {
      const c = (seg.text && seg.text.content) || '';
      const urnMatch = c.match(/urn:[\w:]+/);
      if (urnMatch) existingUrns.add(urnMatch[0]);
    }
  }
}
const newPosts = posts.filter(p => !existingUrls.has(p.url) && !existingUrns.has(p.urn));
return newPosts.map(p => ({ json: p }));

