    if (String(idea.relevance || '').toLowerCase() === 'low' && String(idea.utility || '').toLowerCase() === 'low') continue;
    out.push({ json: {
      topic_headline: idea.topic_headline || '',
      hook: idea.hook || '',
      key_points: idea.key_points || [],
      observations: idea.observations || [],
      tips: idea.tips || [],
      quotes: idea.quotes || [],
      audience: idea.audience || [],
      hot_take_potential: idea.hot_take_potential || 'Medium',
      utility: idea.utility || 'Medium',
      relevance: idea.relevance || 'Medium',
      format: idea.format || 'Explainer',
      draft_angle: idea.draft_angle || '',
      why_it_matters: idea.why_it_matters || '',
      further_reading: idea.further_reading || [],
      merged_topics: Array.from(merged),
      podcast_name: 'LinkedIn — ' + (($("Carry Source Context").item.json._author_name) || ''),
      episode_title: 'LinkedIn post by ' + (($("Carry Source Context").item.json._author_name) || ''),
      episode_url: ($("Carry Source Context").item.json._post_url) || '',
      episode_published: ($("Carry Source Context").item.json._posted_at) || '',
      source_page_id: ($("Carry Source Context").item.json.source_page_id) || '',
      source_type: 'linkedin',
      transcript_id: ($("Carry Source Context").item.json._urn) || '',
      transcript_source: 'LinkedIn',
      extraction_model: 'Sonnet 4.6',
    } });
  }
}
return out;

